import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import AppLayout from '../components/shared/AppLayout';
import LoadingSpinner from '../components/shared/LoadingSpinner';
import api from '../utils/api';
import { format } from 'date-fns';

const PrizeBadge = ({ tier }) => {
  const map = {
    gold: 'prize-gold',
    silver: 'prize-silver',
    bronze: 'prize-bronze',
  };
  return (
    <span className={`text-xs font-bold uppercase tracking-wider px-2 py-0.5 rounded-full border ${map[tier] || ''}`}>
      {tier}
    </span>
  );
};

export default function DashboardPage() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get('/users/dashboard')
      .then(r => setData(r.data.dashboard))
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <AppLayout><div className="flex justify-center mt-20"><LoadingSpinner size="lg" text="Loading dashboard..." /></div></AppLayout>;

  const { user, scores, wins, total_wins, gold_wins, silver_wins, bronze_wins } = data;
  const isActive = user.subscription_status === 'active';

  return (
    <AppLayout>
      <div className="max-w-5xl mx-auto space-y-8 animate-slide-up">
        {/* Header */}
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div>
            <h1 className="page-title">Good to see you, {user.name.split(' ')[0]} 👋</h1>
            <p className="text-charcoal-400 mt-1">Here's your Golf Charity overview</p>
          </div>
          <div className={isActive ? 'badge-active' : 'badge-inactive'}>
            <span className={`w-2 h-2 rounded-full ${isActive ? 'bg-forest-500 animate-pulse-slow' : 'bg-charcoal-500'}`} />
            {isActive ? `${user.plan} plan` : 'No active plan'}
          </div>
        </div>

        {/* Subscription CTA */}
        {!isActive && (
          <div className="card border border-gold-700/30 bg-gold-900/10">
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
              <div>
                <h3 className="font-display font-semibold text-white mb-1">Subscribe to start playing</h3>
                <p className="text-charcoal-400 text-sm">You need an active subscription to add scores and enter draws.</p>
              </div>
              <Link to="/subscription" className="btn-gold shrink-0">Choose a Plan</Link>
            </div>
          </div>
        )}

        {/* Stats */}
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="stat-card">
            <div className="stat-number">{scores.length}</div>
            <div className="stat-label">Scores logged</div>
          </div>
          <div className="stat-card">
            <div className="stat-number text-gold-400">{gold_wins}</div>
            <div className="stat-label">Gold wins</div>
          </div>
          <div className="stat-card">
            <div className="stat-number text-charcoal-300">{silver_wins}</div>
            <div className="stat-label">Silver wins</div>
          </div>
          <div className="stat-card">
            <div className="stat-number text-amber-600">{bronze_wins}</div>
            <div className="stat-label">Bronze wins</div>
          </div>
        </div>

        {/* Two-col layout */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Recent Scores */}
          <div className="card">
            <div className="flex items-center justify-between mb-5">
              <h2 className="section-title">Recent Scores</h2>
              <Link to="/scores" className="text-forest-400 hover:text-forest-300 text-sm font-medium">Manage →</Link>
            </div>
            {scores.length === 0 ? (
              <div className="text-center py-8">
                <div className="text-4xl mb-3">⛳</div>
                <p className="text-charcoal-400 text-sm">No scores yet.</p>
                {isActive && <Link to="/scores" className="btn-primary mt-4 text-sm py-2 px-4 inline-block">Add First Score</Link>}
              </div>
            ) : (
              <div className="space-y-2">
                {scores.map((s, i) => (
                  <div key={s._id} className="flex items-center gap-3 p-3 rounded-xl bg-charcoal-800/40 hover:bg-charcoal-800/60 transition-colors">
                    <div className={`score-bubble ${i === 0 ? 'bg-forest-800 text-forest-300 border border-forest-700' : 'bg-charcoal-700 text-charcoal-300'}`}>
                      {s.score}
                    </div>
                    <div>
                      <div className="text-sm font-medium text-white">Score: {s.score} pts</div>
                      <div className="text-xs text-charcoal-500">{format(new Date(s.date), 'MMM dd, yyyy')}</div>
                    </div>
                    {i === 0 && <span className="ml-auto text-xs text-forest-500 font-medium">Latest</span>}
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Charity & Wins */}
          <div className="space-y-6">
            {/* Charity */}
            <div className="card">
              <div className="flex items-center justify-between mb-4">
                <h2 className="section-title">My Charity</h2>
                <Link to="/charity" className="text-forest-400 hover:text-forest-300 text-sm font-medium">Change →</Link>
              </div>
              {user.charity_id ? (
                <div className="flex items-center gap-4">
                  <div className="w-14 h-14 rounded-xl overflow-hidden bg-charcoal-800 shrink-0">
                    {user.charity_id.image && <img src={user.charity_id.image} alt={user.charity_id.name} className="w-full h-full object-cover" />}
                  </div>
                  <div>
                    <div className="font-medium text-white">{user.charity_id.name}</div>
                    <div className="text-sm text-forest-400 font-medium">{user.charity_percentage}% contribution</div>
                  </div>
                </div>
              ) : (
                <div className="text-center py-4">
                  <p className="text-charcoal-400 text-sm mb-3">No charity selected</p>
                  <Link to="/charity" className="btn-primary text-sm py-2 px-4 inline-block">Select Charity</Link>
                </div>
              )}
            </div>

            {/* Recent Wins */}
            <div className="card">
              <div className="flex items-center justify-between mb-4">
                <h2 className="section-title">Recent Wins</h2>
                <Link to="/draws" className="text-forest-400 hover:text-forest-300 text-sm font-medium">All →</Link>
              </div>
              {wins.length === 0 ? (
                <p className="text-charcoal-500 text-sm text-center py-4">No wins yet — keep playing! 🎯</p>
              ) : (
                <div className="space-y-2">
                  {wins.slice(0, 3).map(w => (
                    <div key={w._id} className="flex items-center justify-between p-3 rounded-xl bg-charcoal-800/40">
                      <div>
                        <div className="text-sm text-white">{w.match_count} matches</div>
                        <div className="text-xs text-charcoal-500">{w.draw_id?.month}</div>
                      </div>
                      <PrizeBadge tier={w.prize_tier} />
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </AppLayout>
  );
}
